event_inherited() image_speed=0 visible=0 bCanTakeDamage=false bCanDealDamage=false detectDistX=192 detectDistY=160
myColor=irandom_range(1,4) if myColor=1 {baseColor=c_red; image_blend=baseColor} else if myColor=2 {baseColor=c_blue; image_blend=baseColor} else if myColor=3 {baseColor=c_green; image_blend=baseColor} else if myColor=4 {baseColor=c_yellow; image_blend=baseColor}
